public final class TransactionProcessor {
    private let store: BankingStore
    private let queue = DispatchQueue(label: "banking.processor.serial", qos: .userInitiated)

    public init(store: BankingStore) {
        self.store = store
    }

    public func createAccount(name: String, openingBalance: Money) async throws -> Account {
        guard openingBalance.amountMinor >= 0 else { throw BankingError.invalidAmount }
        return try await withCheckedThrowingContinuation { cont in
            queue.async {
                Task {
                    do {
                        var snap = try await self.store.load()
                        let account = Account(name: name, balance: openingBalance, updatedAt: Date())
                        snap.accounts.append(account)
                        try await self.store.save(snap)
                        cont.resume(returning: account)
                    } catch {
                        cont.resume(throwing: error)
                    }
                }
            }
        }
    }

    public func getAccounts() async throws -> [Account] {
        let snap = try await store.load()
        return snap.accounts.sorted { $0.name.localizedCaseInsensitiveCompare($1.name) == .orderedAscending }
    }

    public func getTransactions(accountId: UUID) async throws -> [Transaction] {
        let snap = try await store.load()
        return snap.transactions
            .filter { $0.accountId == accountId }
            .sorted { $0.createdAt > $1.createdAt }
    }

    public func postTransaction(_ tx: Transaction) async throws -> Transaction {
        guard tx.amount.amountMinor > 0 else { throw BankingError.invalidAmount }

        return try await withCheckedThrowingContinuation { cont in
            queue.async {
                Task {
                    do {
                        var snap = try await self.store.load()

                        guard let idx = snap.accounts.firstIndex(where: { $0.id == tx.accountId }) else {
                            throw BankingError.accountNotFound
                        }

                        if snap.transactions.contains(where: { $0.id == tx.id }) {
                            throw BankingError.duplicateTransaction
                        }

                        var account = snap.accounts[idx]
                        guard account.balance.currency == tx.amount.currency else { throw BankingError.currencyMismatch }

                        var newBalance = account.balance
                        switch tx.direction {
                        case .credit:
                            newBalance = newBalance + tx.amount
                        case .debit:
                            if newBalance.amountMinor < tx.amount.amountMinor { throw BankingError.insufficientFunds }
                            newBalance = newBalance - tx.amount
                        }

                        account.balance = newBalance
                        account.updatedAt = Date()
                        snap.accounts[idx] = account

                        var posted = tx
                        posted.status = .posted
                        snap.transactions.append(posted)

                        try await self.store.save(snap)
                        cont.resume(returning: posted)
                    } catch {
                        cont.resume(throwing: error)
                    }
                }
            }
        }
    }
}

