public final class AccountsViewController: UITableViewController {
    private let processor: TransactionProcessor
    private let formatter: MoneyFormatter
    private var accounts: [Account] = []

    public init(processor: TransactionProcessor, formatter: MoneyFormatter = MoneyFormatter()) {
        self.processor = processor
        self.formatter = formatter
        super.init(style: .insetGrouped)
        self.title = "Accounts"
        self.navigationItem.rightBarButtonItem = UIBarButtonItem(title: "Add", style: .plain, target: self, action: #selector(addAccount))
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    public override func viewDidLoad() {
        super.viewDidLoad()
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
        Task { await reload() }
    }

    private func reloadUI() {
        tableView.reloadData()
    }

    @MainActor private func setAccounts(_ accounts: [Account]) {
        self.accounts = accounts
        reloadUI()
    }

    private func reload() async {
        do {
            let list = try await processor.getAccounts()
            await MainActor.run { self.setAccounts(list) }
        } catch {
            await MainActor.run { self.presentError(error) }
        }
    }

    @objc private func addAccount() {
        let alert = UIAlertController(title: "New Account", message: "Create an account", preferredStyle: .alert)
        alert.addTextField { $0.placeholder = "Name" }
        alert.addTextField {
            $0.placeholder = "Opening balance (e.g., 100.00)"
            $0.keyboardType = .decimalPad
        }
        alert.addTextField {
            $0.placeholder = "Currency (e.g., USD)"
            $0.autocapitalizationType = .allCharacters
            $0.text = Locale.current.currency?.identifier ?? "USD"
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Create", style: .default) { [weak self] _ in
            guard let self else { return }
            let name = alert.textFields?[0].text?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let openingString = alert.textFields?[1].text?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "0"
            let currency = (alert.textFields?[2].text?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "USD").uppercased()

            let minor = Self.parseMoneyToMinor(openingString)
            Task {
                do {
                    _ = try await self.processor.createAccount(name: name.isEmpty ? "Account" : name, openingBalance: Money(currency: currency, amountMinor: minor))
                    await self.reload()
                } catch {
                    await MainActor.run { self.presentError(error) }
                }
            }
        })
        present(alert, animated: true)
    }

    public override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        accounts.count
    }

    public override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        let account = accounts[indexPath.row]
        var content = cell.defaultContentConfiguration()
        content.text = account.name
        content.secondaryText = formatter.string(account.balance)
        cell.contentConfiguration = content
        cell.accessoryType = .disclosureIndicator
        return cell
    }

    public override func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let account = accounts[indexPath.row]
        let vc = AccountDetailViewController(processor: processor, account: account, formatter: formatter)
        navigationController?.pushViewController(vc, animated: true)
    }

    @MainActor private func presentError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: (error as? LocalizedError)?.errorDescription ?? error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }

    private static func parseMoneyToMinor(_ s: String) -> Int64 {
        let normalized = s.replacingOccurrences(of: ",", with: ".")
        let comps = normalized.split(separator: ".", omittingEmptySubsequences: false)
        let whole = Int64(comps.first ?? "0") ?? 0
        let frac: Int64
        if comps.count > 1 {
            let f = String(comps[1])
            let two = (f + "00").prefix(2)
            frac = Int64(two) ?? 0
        } else {
            frac = 0
        }
        return whole * 100 + (whole >= 0 ? frac : -frac)
    }
}

public final class AccountDetailViewController: UITableViewController {
    private let processor: TransactionProcessor
    private let formatter: MoneyFormatter
    private var account: Account
    private var transactions: [Transaction] = []

    public init(processor: TransactionProcessor, account: Account, formatter: MoneyFormatter = MoneyFormatter()) {
        self.processor = processor
        self.account = account
        self.formatter = formatter
        super.init(style: .insetGrouped)
        self.title = account.name
        self.navigationItem.rightBarButtonItems = [
            UIBarButtonItem(title: "Pay", style: .plain, target: self, action: #selector(addDebit)),
            UIBarButtonItem(title: "Deposit", style: .plain, target: self, action: #selector(addCredit))
        ]
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    public override func viewDidLoad() {
        super.viewDidLoad()
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
        Task { await reload() }
    }

    public override func numberOfSections(in tableView: UITableView) -> Int { 2 }

    public override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        section == 0 ? 1 : transactions.count
    }

    public override func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        section == 0 ? "Balance" : "Transactions"
    }

    public override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        var content = cell.defaultContentConfiguration()
        if indexPath.section == 0 {
            content.text = formatter.string(account.balance)
            content.secondaryText = "Updated \(Self.relativeDate(account.updatedAt))"
            cell.selectionStyle = .none
        } else {
            let tx = transactions[indexPath.row]
            let sign = (tx.direction == .debit) ? "−" : "+"
            content.text = "\(sign)\(formatter.string(tx.amount))"
            content.secondaryText = [tx.memo, Self.relativeDate(tx.createdAt), tx.status.rawValue.capitalized]
                .compactMap { $0?.isEmpty == false ? $0 : nil }
                .joined(separator: " • ")
            cell.selectionStyle = .none
        }
        cell.contentConfiguration = content
        return cell
    }

    private func reload() async {
        do {
            let accounts = try await processor.getAccounts()
            if let updated = accounts.first(where: { $0.id == account.id }) {
                await MainActor.run { self.account = updated; self.title = updated.name }
            }
            let txs = try await processor.getTransactions(accountId: account.id)
            await MainActor.run { self.transactions = txs; self.tableView.reloadData() }
        } catch {
            await MainActor.run { self.presentError(error) }
        }
    }

    @objc private func addDebit() { presentTransaction(direction: .debit) }
    @objc private func addCredit() { presentTransaction(direction: .credit) }

    private func presentTransaction(direction: TransactionDirection) {
        let title = direction == .debit ? "New Payment" : "New Deposit"
        let alert = UIAlertController(title: title, message: "Enter amount", preferredStyle: .alert)
        alert.addTextField {
            $0.placeholder = "Amount (e.g., 12.34)"
            $0.keyboardType = .decimalPad
        }
        alert.addTextField { $0.placeholder = "Memo (optional)" }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Post", style: .default) { [weak self] _ in
            guard let self else { return }
            let amountString = alert.textFields?[0].text?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "0"
            let memo = alert.textFields?[1].text?.trimmingCharacters(in: .whitespacesAndNewlines)
            let minor = AccountsViewController.parseMoneyToMinor(amountString)
            Task {
                do {
                    let tx = Transaction(
                        accountId: self.account.id,
                        direction: direction,
                        amount: Money(currency: self.account.balance.currency, amountMinor: minor),
                        memo: memo?.isEmpty == true ? nil : memo,
                        status: .pending
                    )
                    _ = try await self.processor.postTransaction(tx)
                    await self.reload()
                } catch {
                    await MainActor.run { self.presentError(error) }
                }
            }
        })
        present(alert, animated: true)
    }

    @MainActor private func presentError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: (error as? LocalizedError)?.errorDescription ?? error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }

    private static func relativeDate(_ date: Date) -> String {
        let f = RelativeDateTimeFormatter()
        f.unitsStyle = .short
        return f.localizedString(for: date, relativeTo: Date())
    }
}

// MARK: - Module Factory

public enum BankingModule {
    public static func makeRootViewController() -> UIViewController {
        let keychain = KeychainStore(config: .init(service: "com.example.BankingModule", account: "banking.masterkey"))
        let auth = LocalAuthProvider()
        let crypto = CryptoBox(keychain: keychain, auth: auth)

        let url = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
            .appendingPathComponent("BankingModule", isDirectory: true)
            .appendingPathComponent("banking.enc")

        let store = EncryptedFileBankingStore(url: url, crypto: crypto)
        let processor = TransactionProcessor(store: store)
        let root = AccountsViewController(processor: processor)

        let nav = UINavigationController(rootViewController: root)
        nav.navigationBar.prefersLargeTitles = true
        return nav
    }
}